            )}
        </div>

        {/* Continue Game Card - Takes 7 cols */}
        <div className="lg:col-span-7 bg-white p-8 rounded-3xl shadow-xl border border-indigo-50 flex flex-col justify-between items-start relative overflow-hidden hover:shadow-2xl transition-all">
            <div className="z-10 relative">
                <h2 className="text-3xl font-bold mb-4 text-gray-800 flex items-center gap-2">
                    <Book className="text-green-500 w-8 h-8"/> Continue Journey
