                <div className="text-center py-20 text-gray-500">
                    <p>No stories found matching "{searchQuery}".</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredSlots.map(slot => (
                        <div 
                            key={slot.id}
                            className="group bg-white rounded-2xl shadow-md border border-gray-100 hover:shadow-xl hover:border-indigo-200 transition-all overflow-hidden flex flex-col relative"
