                            <div className="h-48 bg-gray-100 relative overflow-hidden">
                                {slot.characterImage ? (
                                    <img src={slot.characterImage} alt={slot.characterName} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
